/**
 * @brief Checks if a number n is "valid" based on the digit x.
 * 
 * A number is valid if:
 * 1. It contains at least one digit x.
 * 2. It does not start with the digit x.
 * 
 * @param n The input number (0 <= n <= 10^5).
 * @param x The target digit (0 <= x <= 9).
 * @return true if n is valid, false otherwise.
 */
bool solve(long long n, int x) {
    // Convert n to string for easy digit checking
    std::string s = std::to_string(n);
    char char_x = x + '0';

    // Condition 1: Check if n contains at least one digit x
    bool contains_x = false;
    for (char c : s) {
        if (c == char_x) {
            contains_x = true;
            break;
        }
    }

    if (!contains_x) {
        return false;
    }

    // Condition 2: Check if n does not start with the digit x
    // The first character of the string s is s[0]
    bool starts_with_x = (s[0] == char_x);

    if (starts_with_x) {
        return false;
    }

    // If both conditions are met
    return true;
}
